<template>
  <div>
    <h3>评分项名称（必填）</h3>
    <van-field
      v-model="form.ruleName"
      autosize
      type="input"
      placeholder="请输入"
      vertical
    />
    <h3 style="margin-top: 16px;">评分项描述</h3>
    <van-field
      v-model="form.description"
      autosize
      rows="3"
      type="textarea"
      placeholder="请输入"
      vertical
    />
    <h3 style="margin-top: 16px;">评分项分数（必填）</h3>
    <van-field
      v-model="form.maxScore"
      autosize
      type="input"
      placeholder="请输入"
      vertical
    />
    <h3 style="margin-top: 16px;">限制最低分（必填）</h3>
    <van-field
      v-model="form.minScore"
      autosize
      type="input"
      placeholder="请输入"
      vertical
    />
    <h3 style="margin-top: 16px;">评分项权重</h3>
    <van-field
      v-model="form.weight"
      autosize
      type="input"
      placeholder="请输入"
      vertical
    />
    <a-button type="primary" style="width: 100%; height: 48px; margin-top: 16px; font-size: 24px;" @click="save">
      {{ this.$route.name === 'scoreRuleDetail' ? '修改' : this.$route.name === 'scoreRuleAdd' ? '新建' : '保存' }}
    </a-button>
  </div>
</template>
<script>
import ListItem from '@/components/ListItem.vue'
import { addTotalScoreItem, getScoreRuleItem, updateTotalScoreItem } from '@/api/scoreRule'
export default {
  components: { ListItem },
  data() {
    return {
      form: {
        voteId: null,
        ruleName: '',
        weight: '',
        maxScore: '',
        minScore: '',
        description: '',
        displayOrder: 1,
      },
    }
  },
  mounted() {
    if (this.$route.name === 'scoreRuleDetail') {
      getScoreRuleItem(this.$route.params.id, this.$route.params.srid).then(res => {
        this.form = res
      })
    } else if (this.$route.name === 'scoreRuleAdd') {
      this.form.voteId = this.$route.params.id
    }
  },
  methods: {
    save() {
      if (this.$route.name === 'scoreRuleDetail') {
        updateTotalScoreItem(this.form).then(res => {
          this.$message.success('已修改')
          this.$router.go(-1)
        })
      } else if (this.$route.name === 'scoreRuleAdd') {
        addTotalScoreItem(this.form).then(res => {
          this.$message.success('已添加')
          this.$router.go(-1)
        })
      }
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 0px !important;
}
::v-deep .van-cell__title {
  span {
    color: #333;
    font-size: 20px;
  }
}
::v-deep .van-field__control, .van-cell__value {
  font-size: 20px;
}
::v-deep .ant-list-item {
  padding: 12px;
  font-size: 16px;
}
</style>
