import request from '@/utils/request'

export function getScoreRuleList(id) {
  return request({
    url: `/scoreRule/selectAllScoreRule?voteId=${id}&page=1&size=100`,
    method: 'get',
  })
}

export function getScoreRuleItem(voteId, ruleId) {
  return request({
    url: `/scoreRule/getDetails?voteId=${voteId}&id=${ruleId}`,
    method: 'get',
  })
}

export function delScoreRuleItem(ruleId) {
  return request({
    url: `/scoreRule/delete?id=${ruleId}`,
    method: 'post',
  })
}

export function getTotalScore(voteId) {
  return request({
    url: `/scoreRule/getTotalScore?voteId=${voteId}`,
    method: 'get',
  })
}

export function addTotalScoreItem(data) {
  return request({
    url: `/scoreRule/add`,
    method: 'post',
    data: data,
  })
}

export function updateTotalScoreItem(data) {
  return request({
    url: `/scoreRule/update`,
    method: 'post',
    data: data,
  })
}
